using namespace std;

class Solution {
public:
    int n;
    vector<int> queens;

    int totalNQueens(int n) {
        this->n = n;
        queens = vector<int>();
        int count = backtrack(n);
        return count;
    }

    int backtrack(int n) {
        if (queens.size() == n) {
            return 1;
        }
        int count = 0;
        for (int i = 0; i < n; i++) {
            if (isValid(i)) {
                queens.push_back(i);
                count += backtrack(n);
                queens.pop_back();
            }
        }
        return count;
    }

    bool isValid(int i) {
        for (int j = 0; j < i; j++) {
            if (queens[j] == i || queens[j] - j == i - j || queens[j] + j == i + j) {
                return false;
            }
        }
        return true;
    }

